const items = $input.all();

// Se não tem posts, retorna vazio
if (!items.length) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Nenhum post aguardando aprovação'
    }
  }];
}

// Pega apenas o PRIMEIRO post aguardando aprovação
const post = items[0].json;

// Valida se o post tem os dados necessários
if (!post.id_post || !post.Blog) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Post inválido: faltam dados essenciais'
    }
  }];
}

// Prepara as URLs das imagens (filtra vazias)
const imagens = [
  post.imagem1_url,
  post.imagem2_url,
  post.imagem3_url,
  post.imagem4_url,
  post.imagem5_url,
  post.imagem6_url,
  post.imagem7_url
].filter(url => url && url.trim() !== '');

// Verifica se tem pelo menos 1 imagem
if (!imagens.length) {
  return [{
    json: {
      tem_posts: false,
      mensagem: 'Post sem imagens válidas'
    }
  }];
}

// Retorna o post completo + metadados extras
return [{
  json: {
    ...post, // <-- inclui todos os campos originais do JSON
    tem_posts: true,
    quantidade_imagens: imagens.length,
    imagem_principal: imagens[0], // primeira imagem (capa)
    imagens: imagens, // lista com todas as imagens válidas
    data_processamento: new Date().toISOString(),
    mensagem: `Post ${post.id_post} preparado para análise do AI Agent`
  }
}];

// Pega o item atual
const item = $input.item.json;

try {
  // 1️⃣ Obtém o conteúdo bruto da IA
  let aiResponse = item.output || item.data || item.response || item.message || item;

  // 2️⃣ Se vier como string, remove formatação markdown e tenta parsear
  if (typeof aiResponse === 'string') {
    aiResponse = aiResponse
      .replace(/```json\n?/g, '')  // remove ```json
      .replace(/```\n?/g, '')      // remove ```
      .replace(/^json/, '')        // remove "json" no início se existir
      .trim();

    aiResponse = JSON.parse(aiResponse);
  }

  // 3️⃣ Se for array, pega o primeiro elemento
  if (Array.isArray(aiResponse)) {
    aiResponse = aiResponse[0];
  }

  // 4️⃣ Validação básica
  if (!aiResponse.id_post) {
    throw new Error('Campo "id_post" não encontrado na resposta da IA');
  }

  // 5️⃣ Retorna os campos completos e simplificados
  return {
    json: {
      id_post: aiResponse.id_post,
      status: aiResponse.status,
      status_linkedin: aiResponse.status_linkedin,
      nota_final: aiResponse.nota_final,
      nota_final_linkedin: aiResponse.nota_final_linkedin,
      notas_detalhadas: {
        visual: aiResponse.notas_detalhadas?.visual ?? null,
        legenda: aiResponse.notas_detalhadas?.legenda ?? null,
        relevancia: aiResponse.notas_detalhadas?.relevancia ?? null
      },
      categoria_visual: aiResponse.categoria_visual,
      categoria_legenda: aiResponse.categoria_legenda,
      categoria_relevancia: aiResponse.categoria_relevancia,
      justificativa: aiResponse.justificativa,
      pontos_fortes: aiResponse.pontos_fortes || [],
      pontos_fracos: aiResponse.pontos_fracos || [],
      recomendacao: aiResponse.recomendacao
    }
  };

} catch (error) {
  // 6️⃣ Em caso de erro, retorna uma estrutura de erro legível
  return {
    json: {
      erro: true,
      mensagem: error.message,
      item_original: item
    }
  };
}

// Inicializa o array de resultados
const results = [];

for (const item of $input.all()) {
  try {
    // 1️⃣ Pega o conteúdo retornado pela IA
    const rawContent = item.json.content;

    // 2️⃣ Remove formatação Markdown (caso exista) e espaços extras
    const cleanJson = rawContent
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    // 3️⃣ Faz o parsing do JSON interno
    const parsed = JSON.parse(cleanJson);

    // 4️⃣ Retorna os campos principais organizados
    results.push({
      json: {
        decisao_geral: parsed.decisao_geral,
        analise_detalhada: parsed.analise_detalhada,
        recomendacao_final: parsed.recomendacao_final,
      },
    });
  } catch (error) {
    // 5️⃣ Em caso de erro, retorna o erro e o conteúdo original
    results.push({
      json: {
        error: error.message,
        raw_content: item.json.content,
      },
    });
  }
}

// 6️⃣ Retorna todos os resultados processados
return results;
